<h1 class="h3 mb-1">Customer Scheduling Requests</h1><p class="text-muted mb-4">Review preferred dates and convert approved requests into scheduled jobs.</p><div class="card shadow-sm"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Customer</th><th>Service</th><th>Preferred</th><th>Property</th><th>Status</th><th>Decision</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['display_name'])?></strong><div class="small text-muted"><?=e($r['notes'])?></div></td><td><?=e($r['service_name']?:'General service')?></td><td><?=e($r['preferred_date'])?> <span class="text-muted"><?=e($r['preferred_window'])?></span><?php if($r['alternate_date']):?><div class="small">Alternate: <?=e($r['alternate_date'])?></div><?php endif?></td><td><?=e($r['property_address'])?></td><td><span class="badge text-bg-secondary"><?=e($r['status'])?></span></td><td><?php if($r['status']==='requested'):?><form method="post" action="/portal/scheduling-requests/<?=e($r['id'])?>/decide" class="row g-1"><?=csrf_field()?><div class="col-12"><input type="datetime-local" name="scheduled_start" class="form-control form-control-sm"></div><div class="col-12"><select name="assigned_user_id" class="form-select form-select-sm"><option value="">Unassigned</option><?php foreach($users as $u):?><option value="<?=e($u['id'])?>"><?=e($u['name'])?></option><?php endforeach?></select></div><div class="col"><button name="decision" value="scheduled" class="btn btn-sm btn-primary">Schedule</button></div><div class="col"><button name="decision" value="declined" class="btn btn-sm btn-outline-danger">Decline</button></div></form><?php else:?><?=e($r['job_id']?'Job #'.$r['job_id']:'Reviewed')?><?php endif?></td></tr><?php endforeach?></tbody></table></div></div>
